export type Cell = [number, number];

const key = (x: number, y: number): string => `${x},${y}`;

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const alive = new Set(liveCells.map(([x, y]) => key(x, y)));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        candidates.set(key(x + dx, y + dy), [x + dx, y + dy]);
      }
    }
  }
  const result: Cell[] = [];
  for (const [k, [x, y]] of candidates) {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (alive.has(key(x + dx, y + dy))) count++;
      }
    }
    const isAlive = alive.has(k);
    if (isAlive && (count === 2 || count === 3)) result.push([x, y]);
    else if (!isAlive && count === 3) result.push([x, y]);
  }
  return result;
};

